// priceCalculator.js
function calculateTotal(items, taxRate) {
  const subtotal = items.reduce((sum, item) => sum + item.price * item.qty, 0);
  const tax = Math.round(subtotal * taxRate);
  return { subtotal, tax, total: subtotal + tax };
}

// priceCalculator.test.js
const { calculateTotal } = require('./priceCalculator');

describe('calculateTotal', () => {
  it('sums item prices and applies tax', () => {
    const items = [
      { price: 1000, qty: 2 },
      { price: 500,  qty: 1 }
    ];
    const result = calculateTotal(items, 0.08);
    expect(result.subtotal).toBe(2500);
    expect(result.tax).toBe(200);
    expect(result.total).toBe(2700);
  });

  it('returns zero for empty cart', () => {
    const result = calculateTotal([], 0.08);
    expect(result.total).toBe(0);
  });
});

